import{_ as a,o as l,c as i,a2 as n}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"OpenClaw Practices","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/tooling/openclaw.md","filePath":"ai-native/tooling/openclaw.md"}'),o={name:"ai-native/tooling/openclaw.md"};function t(s,e,r,d,p,c){return l(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="openclaw-practices" tabindex="-1">OpenClaw Practices <a class="header-anchor" href="#openclaw-practices" aria-label="Permalink to &quot;OpenClaw Practices&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>最后核对：2026-06-15</strong></p><p>本指南面向官方 <a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer"><code>openclaw/openclaw</code></a>，重点说明其作为飞书常驻协作 Agent 的组织级采用方式。</p><p>OpenClaw 的定位不是组织知识真源，也不是无边界的自动执行者。它是连接团队消息、Agent Session、Skill 和受控工具的常驻 Gateway。</p><p>官方 Feishu Channel 要求 OpenClaw <code>2026.5.29</code> 或更高版本。团队实例升级前应在测试环境核对 Channel、Session、Skill 和权限行为。</p><h2 id="推荐定位" tabindex="-1">推荐定位 <a class="header-anchor" href="#推荐定位" aria-label="Permalink to &quot;推荐定位&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>飞书</span></span>
<span class="line"><span>  人类提出任务、补充上下文、批准高风险动作</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>OpenClaw</span></span>
<span class="line"><span>  接收、澄清、路由、跟踪、定时和汇报</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>专业 Agent / 受控工具</span></span>
<span class="line"><span>  Codex、Claude Code、Feishu CLI、项目 Skill</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>可审查交付物</span></span>
<span class="line"><span>  PR、Issue、文档草稿、任务记录、验证证据</span></span></code></pre></div><h3 id="openclaw-适合负责" tabindex="-1">OpenClaw 适合负责 <a class="header-anchor" href="#openclaw-适合负责" aria-label="Permalink to &quot;OpenClaw 适合负责&quot;">​</a></h3><ul><li>在飞书中提供统一的任务入口</li><li>收集目标、上下文、约束和完成条件</li><li>将请求路由到隔离的 Agent 或 Session</li><li>运行已批准的稳定 Skill 和定时任务</li><li>汇总进度、阻塞、结果和待确认事项</li><li>将候选经验转成 Issue、Draft PR 或 Observation</li></ul><h3 id="openclaw-不应默认负责" tabindex="-1">OpenClaw 不应默认负责 <a class="header-anchor" href="#openclaw-不应默认负责" aria-label="Permalink to &quot;OpenClaw 不应默认负责&quot;">​</a></h3><ul><li>单独批准发布、结算、权限和生产数据修改</li><li>把群聊内容自动晋升为组织规则</li><li>以一个共享 Session 服务多个需要隐私隔离的成员</li><li>在不受控的 Host 环境执行任意 Shell</li><li>将飞书聊天记录作为项目或组织的长期真源</li></ul><h2 id="feishu-channel-配置原则" tabindex="-1">Feishu Channel 配置原则 <a class="header-anchor" href="#feishu-channel-配置原则" aria-label="Permalink to &quot;Feishu Channel 配置原则&quot;">​</a></h2><h3 id="_1-群聊默认-allowlist" tabindex="-1">1. 群聊默认 Allowlist <a class="header-anchor" href="#_1-群聊默认-allowlist" aria-label="Permalink to &quot;1. 群聊默认 Allowlist&quot;">​</a></h3><ul><li><code>groupPolicy</code> 保持 <code>allowlist</code></li><li>群聊默认要求 <code>@mention</code></li><li>只允许明确登记的群和成员触发 Agent</li><li>不因“内部群”而关闭所有发送者限制</li></ul><p>OpenClaw 官方 Feishu Channel 默认要求群聊 Allowlist 和 @mention，这适合作为团队基线。</p><h3 id="_2-私聊必须隔离" tabindex="-1">2. 私聊必须隔离 <a class="header-anchor" href="#_2-私聊必须隔离" aria-label="Permalink to &quot;2. 私聊必须隔离&quot;">​</a></h3><p>多人可以私聊同一个 Bot 时，使用按 Channel 和 Sender 隔离的 Session。否则不同成员可能共享对话上下文。</p><p>动态 Agent 可以为每个成员创建独立 Workspace、Memory 和会话，但这是消息上下文隔离，不是敌对租户级安全边界。</p><h3 id="_3-按职责路由-agent" tabindex="-1">3. 按职责路由 Agent <a class="header-anchor" href="#_3-按职责路由-agent" aria-label="Permalink to &quot;3. 按职责路由 Agent&quot;">​</a></h3><p>不要让一个 Agent 同时拥有所有知识和工具。推荐至少区分：</p><table tabindex="0"><thead><tr><th>Agent</th><th>主要职责</th><th>默认权限</th></tr></thead><tbody><tr><td><code>team-coordinator</code></td><td>澄清、路由、汇报、知识候选</td><td>飞书读写，有限 Session 工具</td></tr><tr><td><code>engineering</code></td><td>代码任务和 PR 交付</td><td>指定仓库 Workspace，受控 Shell</td></tr><tr><td><code>knowledge</code></td><td>Handbook 草稿和索引维护</td><td>Handbook 只读或分支写入</td></tr><tr><td><code>operations</code></td><td>定时检查和状态汇总</td><td>只读 API，写操作单独批准</td></tr></tbody></table><p>实际 Agent ID、群 ID、成员 ID、Workspace 路径和凭证属于私有运行配置，不进入公共 Handbook。</p><h3 id="_4-非-owner-会话默认-sandbox" tabindex="-1">4. 非 Owner 会话默认 Sandbox <a class="header-anchor" href="#_4-非-owner-会话默认-sandbox" aria-label="Permalink to &quot;4. 非 Owner 会话默认 Sandbox&quot;">​</a></h3><p>团队群和共享入口应：</p><ul><li>使用 Agent 或 Session 级 Sandbox</li><li>默认不给 Host Home Directory</li><li>Workspace 默认只读或无访问</li><li>禁止 <code>gateway</code>、<code>cron</code>、浏览器和高风险 Shell，除非该 Agent 明确需要</li><li>限制可以 Spawn 的 Subagent</li><li>Elevated 权限仅向受控身份开放</li></ul><h3 id="_5-第三方-skill-按代码审查" tabindex="-1">5. 第三方 Skill 按代码审查 <a class="header-anchor" href="#_5-第三方-skill-按代码审查" aria-label="Permalink to &quot;5. 第三方 Skill 按代码审查&quot;">​</a></h3><p>Skill 可以执行代码和调用凭证。安装前：</p><ol><li>阅读 <code>SKILL.md</code>、脚本和依赖。</li><li>确认触发条件不会误匹配。</li><li>在测试 Workspace 和 Sandbox 中运行。</li><li>明确它能访问的数据和 Tool。</li><li>记录版本、来源、Owner 和卸载方式。</li></ol><p>未经审查的 ClawHub 或第三方 Skill 不进入团队实例。</p><h2 id="与-codex-claude-code-的协作" tabindex="-1">与 Codex / Claude Code 的协作 <a class="header-anchor" href="#与-codex-claude-code-的协作" aria-label="Permalink to &quot;与 Codex / Claude Code 的协作&quot;">​</a></h2><p>OpenClaw 负责入口和协调，代码 Agent 负责仓库执行。</p><h3 id="推荐交接包" tabindex="-1">推荐交接包 <a class="header-anchor" href="#推荐交接包" aria-label="Permalink to &quot;推荐交接包&quot;">​</a></h3><p>路由代码任务前，OpenClaw 应整理：</p><ul><li><code>Goal</code></li><li><code>Repository / Workspace</code></li><li><code>Context</code></li><li><code>Constraints</code></li><li><code>Done when</code></li><li><code>Risk level</code></li><li><code>Human approver</code></li><li><code>Return channel / thread</code></li></ul><p>Codex 可通过 OpenClaw 的 ACP Session 绑定到飞书私聊或 Topic Thread。若未启用 ACP，也可以由 OpenClaw 创建结构化任务，再交给独立 Codex 或 Claude Code 会话。</p><p>代码 Agent 返回：</p><ul><li>修改摘要</li><li>PR、Commit 或 Diff 链接</li><li>实际运行的验证</li><li>未验证事项和剩余风险</li><li>需要人类决定的问题</li></ul><p>OpenClaw 不把“Agent 声称完成”视为完成，必须检查交付物和验证证据。</p><h2 id="与-feishu-cli-的关系" tabindex="-1">与 Feishu CLI 的关系 <a class="header-anchor" href="#与-feishu-cli-的关系" aria-label="Permalink to &quot;与 Feishu CLI 的关系&quot;">​</a></h2><ul><li>OpenClaw：对话入口、Session、路由和长期运行</li><li>Feishu CLI：对飞书资源进行结构化、可 Dry Run 的确定性操作</li></ul><p>OpenClaw 需要创建文档、日程、任务或消息时，优先通过受控 Skill 调用 Feishu CLI，而不是把复杂 API 调用直接写进 Prompt。</p><p>写操作仍遵循：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读取 -&gt; Schema -&gt; Dry Run -&gt; 确认 -&gt; 执行 -&gt; 回读</span></span></code></pre></div><h2 id="运行与审计" tabindex="-1">运行与审计 <a class="header-anchor" href="#运行与审计" aria-label="Permalink to &quot;运行与审计&quot;">​</a></h2><p>团队实例至少保留：</p><ul><li>Gateway 和 Channel 健康状态</li><li>Agent、Session 和 Binding 变更记录</li><li>Skill 安装与升级记录</li><li>高风险 Tool 的批准记录</li><li>定时任务的 Owner、频率和停止方式</li><li>失败任务的日志位置和升级路径</li></ul><p>日志不得成为泄露聊天内容、Token 或私密文档的旁路。</p><h2 id="采用清单" tabindex="-1">采用清单 <a class="header-anchor" href="#采用清单" aria-label="Permalink to &quot;采用清单&quot;">​</a></h2><ul><li>[ ] 飞书群和成员采用 Allowlist</li><li>[ ] 群聊默认要求 @mention</li><li>[ ] 多人私聊使用 Session 隔离</li><li>[ ] 不同职责路由到不同 Agent</li><li>[ ] 团队入口默认启用 Sandbox 和最小 Tool</li><li>[ ] 第三方 Skill 已审查和试运行</li><li>[ ] 高风险动作需要人类批准</li><li>[ ] 代码任务返回可审查交付物和验证</li><li>[ ] OpenClaw Memory 不替代 Git 或业务系统真源</li><li>[ ] 运行配置和凭证未进入公共 Handbook</li></ul><h2 id="官方参考" tabindex="-1">官方参考 <a class="header-anchor" href="#官方参考" aria-label="Permalink to &quot;官方参考&quot;">​</a></h2><ul><li><a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">OpenClaw</a></li><li><a href="https://docs.openclaw.ai/channels/feishu" target="_blank" rel="noreferrer">Feishu Channel</a></li><li><a href="https://docs.openclaw.ai/concepts/session" target="_blank" rel="noreferrer">Session management</a></li><li><a href="https://docs.openclaw.ai/tools/skills" target="_blank" rel="noreferrer">Skills</a></li><li><a href="https://docs.openclaw.ai/gateway/security" target="_blank" rel="noreferrer">Security</a></li><li><a href="https://docs.openclaw.ai/gateway/configuration" target="_blank" rel="noreferrer">Configuration</a></li></ul>`,52)])])}const b=a(o,[["render",t]]);export{u as __pageData,b as default};
